import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/SupabaseContext';
import { useBrand } from '../context/BrandContext';

const CATEGORIES = [
  { value: 'general', label: 'General Feedback' },
  { value: 'bug', label: 'Bug Report' },
  { value: 'feature', label: 'Feature Request' },
  { value: 'ux', label: 'Design / UX' },
  { value: 'praise', label: 'Something I Love' },
  { value: 'other', label: 'Other' },
];

export default function FeedbackPage() {
  const { user, supabase, isLoading: authLoading, invokeEdgeFunction } = useAuth();
  const brand = useBrand();
  const navigate = useNavigate();

  const [category, setCategory] = useState('general');
  const [message, setMessage] = useState('');
  const [rating, setRating] = useState<number | null>(null);
  const [hoveredStar, setHoveredStar] = useState<number | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [error, setError] = useState('');

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!message.trim() || message.trim().length < 3) return;
    if (!user) return;

    setSubmitting(true);
    setError('');

    try {
      const payload = {
        user_id: user.id,
        user_email: user.email,
        category,
        message: message.trim(),
        rating,
        page: window.location.href,
      };

      const { error: dbError } = await supabase.from('feedback').insert([payload]);

      if (dbError) {
        // Fallback to edge function if table insert fails
        const { error: fnError } = await invokeEdgeFunction('submit-feedback', {
          category,
          message: message.trim(),
          rating,
          page: window.location.href,
        });
        if (fnError) throw new Error(fnError.message);
      }

      setSubmitted(true);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to submit. Please try again.');
    } finally {
      setSubmitting(false);
    }
  }

  function resetForm() {
    setCategory('general');
    setMessage('');
    setRating(null);
    setSubmitted(false);
    setError('');
  }

  if (authLoading) return null;

  return (
    <div style={{ maxWidth: '640px', margin: '0 auto', padding: '2rem 1.5rem 4rem' }}>
      {/* Header */}
      <div style={{ textAlign: 'center', marginBottom: '1.5rem' }}>
        <div style={{ width: '52px', height: '52px', borderRadius: '2px', background: brand.primaryColor, display: 'inline-flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontSize: '1.3rem', marginBottom: '1rem' }}>
          <i className="fa-solid fa-comment-dots" />
        </div>
        <h1 style={{ fontSize: '1.8rem', margin: '0 0 0.3rem', color: 'var(--text-primary)' }}>Send Feedback</h1>
        <p style={{ margin: 0, fontSize: '0.88rem', color: 'var(--text-secondary)' }}>Help us make TailorMeSwiftly better. We read every single message.</p>
      </div>

      {/* Not logged in */}
      {!user && (
        <div className="glass-panel" style={{ textAlign: 'center', padding: '2rem' }}>
          <i className="fa-solid fa-lock" style={{ fontSize: '1.5rem', color: 'var(--text-secondary)', marginBottom: '0.75rem', display: 'block' }} />
          <p style={{ color: 'var(--text-secondary)', marginBottom: '1rem', fontSize: '0.88rem' }}>Please log in to send feedback so we can follow up with you if needed.</p>
          <button
            onClick={() => navigate('/login')}
            className="btn secondary-btn"
            style={{ display: 'inline-flex', alignItems: 'center', gap: '0.4rem', padding: '0.6rem 1.25rem', cursor: 'pointer' }}
          >
            <i className="fa-solid fa-right-to-bracket" />
            Log In
          </button>
        </div>
      )}

      {/* Success state */}
      {user && submitted && (
        <div className="glass-panel" style={{ textAlign: 'center', padding: '3rem 1.5rem' }}>
          <div style={{ width: '80px', height: '80px', borderRadius: '50%', background: `${brand.primaryColor}15`, display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 1.25rem', fontSize: '2rem', color: brand.primaryColor }}>
            <i className="fa-solid fa-check" />
          </div>
          <h2 style={{ fontSize: '1.4rem', margin: '0 0 0.5rem', color: 'var(--text-primary)' }}>Thank You!</h2>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.88rem', marginBottom: '1.5rem' }}>Your feedback has been received. We genuinely appreciate you taking the time to help us improve.</p>
          <div style={{ display: 'flex', gap: '0.75rem', justifyContent: 'center' }}>
            <Link to="/" className="btn secondary-btn" style={{ display: 'inline-flex', alignItems: 'center', gap: '0.4rem', padding: '0.6rem 1.25rem', textDecoration: 'none' }}>
              <i className="fa-solid fa-home" />
              Back to Home
            </Link>
            <button
              onClick={resetForm}
              className="btn ghost-btn"
              style={{ display: 'inline-flex', alignItems: 'center', gap: '0.4rem', padding: '0.6rem 1.25rem', cursor: 'pointer' }}
            >
              <i className="fa-solid fa-plus" />
              Send More
            </button>
          </div>
        </div>
      )}

      {/* Feedback form */}
      {user && !submitted && (
        <form onSubmit={handleSubmit} className="glass-panel" style={{ padding: '1.75rem' }}>
          {/* Category */}
          <div style={{ marginBottom: '1.5rem' }}>
            <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: 600, marginBottom: '0.4rem', color: 'var(--text-primary)' }}>Category</label>
            <select value={category} onChange={e => setCategory(e.target.value)} style={{ width: '100%' }}>
              {CATEGORIES.map(c => (
                <option key={c.value} value={c.value}>{c.label}</option>
              ))}
            </select>
          </div>

          {/* Star Rating */}
          <div style={{ marginBottom: '1.5rem' }}>
            <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: 600, marginBottom: '0.4rem', color: 'var(--text-primary)' }}>
              How would you rate your experience? <span style={{ fontWeight: 400, color: 'var(--text-secondary)', fontSize: '0.8rem' }}>(optional)</span>
            </label>
            <div style={{ display: 'flex', gap: '0.3rem' }}>
              {[1, 2, 3, 4, 5].map(star => (
                <button
                  key={star}
                  type="button"
                  onClick={() => setRating(rating === star ? null : star)}
                  onMouseEnter={() => setHoveredStar(star)}
                  onMouseLeave={() => setHoveredStar(null)}
                  style={{
                    background: 'transparent',
                    border: 'none',
                    cursor: 'pointer',
                    fontSize: '1.6rem',
                    color: (hoveredStar !== null ? star <= hoveredStar : star <= (rating || 0)) ? '#e2a83e' : 'var(--panel-border)',
                    transition: 'color 0.15s, transform 0.15s',
                    transform: (hoveredStar !== null ? star <= hoveredStar : star <= (rating || 0)) ? 'scale(1.1)' : 'scale(1)',
                    padding: '0.1rem',
                  }}
                >
                  <i className="fa-solid fa-star" />
                </button>
              ))}
            </div>
          </div>

          {/* Message */}
          <div style={{ marginBottom: '1.5rem' }}>
            <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: 600, marginBottom: '0.4rem', color: 'var(--text-primary)' }}>Your Message</label>
            <textarea
              value={message}
              onChange={e => setMessage(e.target.value)}
              placeholder="What's on your mind? Tell us what you like, what's broken, or what you wish existed..."
              maxLength={2000}
              style={{ width: '100%', minHeight: '140px', resize: 'vertical', lineHeight: 1.6 }}
            />
            <div style={{ textAlign: 'right', fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: '0.25rem' }}>
              {message.length.toLocaleString()} / 2,000
            </div>
          </div>

          {/* Error */}
          {error && (
            <div style={{ padding: '0.6rem 0.85rem', borderRadius: '2px', background: 'rgba(239,68,68,0.1)', color: '#ef4444', fontSize: '0.82rem', marginBottom: '1rem' }}>
              <i className="fa-solid fa-triangle-exclamation" style={{ marginRight: '0.3rem' }} />
              {error}
            </div>
          )}

          {/* Submit */}
          <button
            type="submit"
            disabled={submitting || !message.trim() || message.trim().length < 3}
            className="btn secondary-btn"
            style={{
              width: '100%',
              padding: '0.85rem',
              fontSize: '0.95rem',
              cursor: (submitting || !message.trim()) ? 'not-allowed' : 'pointer',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '0.5rem',
            }}
          >
            {submitting ? (
              <><i className="fa-solid fa-spinner fa-spin" /> Sending...</>
            ) : (
              <><i className="fa-solid fa-paper-plane" /> Send Feedback</>
            )}
          </button>
        </form>
      )}
    </div>
  );
}
